qry:select.qry:xquery:
for $r in sql('
	SELECT PER02_PERSONAL_EMP.oi_personal_emp
	FROM PER02_PERSONAL_EMP
	WHERE PER02_PERSONAL_EMP.oi_empresa = {#PARAM:@oi_empresa}
	{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
	{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
	{%  %} 
%}
')/ROWS/ROW

for $r in sql('
	SELECT PER02_PERSONAL_EMP.oi_personal_emp	
	FROM PER02_PERSONAL_EMP
	WHERE PER02_PERSONAL_EMP.oi_empresa_vinc = {#PARAM:@oi_empresa}
	{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
	{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
	{%  %} 
%}
')/ROWS/ROW
